$(function () {
    formSubmission();
    smoothScroll();
    topNavScroll();
    slider();
});

function slider(){
    $('.platforms-slider').slick({
      dots: false,
      swipeToSlide: true,
      arrows: false,
      variableWidth: true
    });
}

function formSubmission() {
    // remove the error upon keydown
    $('form input[type="email"]').on('keydown', function () {
        $(this).removeClass('error');
    });

    $('form').on('submit', function (e) {
        e.preventDefault();

        var input = $(this).find('input[type="email"]');
        if (!validateEmail(input.val())) {
            input.addClass('error');
            return;
        }

        // TODO call the API and submit the form, which wasn't supplied for this example
        $('.form').addClass('success');
    });
}

function smoothScroll() {
    $('a[href*="#"]:not([href="#"])').click(function () {
        if (location.pathname.replace(/^\//, '') == this.pathname.replace(/^\//, '') && location.hostname == this.hostname) {
            var target = $(this.hash);
            target = target.length ? target : $('[name=' + this.hash.slice(1) + ']');
            if (target.length) {
                $('html, body').animate({
                    scrollTop: target.offset().top
                }, 500);
                return false;
            }
        }
    });
}

function topNavScroll() {
    $(window).on('scroll', function (e) {
        var winTop = $(window).scrollTop();
        var headerBottom = $('header').outerHeight();

        if (winTop >= headerBottom) {
            $('nav').addClass("fixed");
        } else {
            $('nav').removeClass("fixed");
        }
    });
}

function validateEmail(email) {
    var re = /^(([^<>()\[\]\\.,;:\s@"]+(\.[^<>()\[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;
    return re.test(email);
}
